module counter_32bit (
    input wire obf_clk,
    input wire reset,
    input wire enable,
    output reg [31:0] count
);
    always @(posedge obf_clk or posedge reset) begin
        if (reset) 
            count <= 32'b0;
        else if (enable) 
            count <= count + 1;
    end
endmodule
